const items = $input.all();
const out = [];
const seen = new Set();
for (const item of items) {
  const links = item.json.links || item.json.data?.links || [];
  for (const l of links) {
    const url = typeof l === 'string' ? l : l.url;
    if (!url) continue;
    if (!url.startsWith('https://bot.zapps.me/docs')) continue;
    if (seen.has(url)) continue;
    seen.add(url);
    out.push({ json: { url } });
  }
}
return out;

// Pure JS hash (no crypto module)
function fnv1a64(str) {
  let h1 = 0x84222325, h2 = 0xcbf29ce4;
  for (let i = 0; i < str.length; i++) {
    const c = str.charCodeAt(i);
    h1 ^= c;
    const lo = h1 * 0x1b3 + (h2 * 0x1b3 << 0);
    const hi = h2 * 0x1b3 + (h1 << 8) + (h1 << 40 / 1);
    h1 = lo >>> 0;
    h2 = (hi + Math.floor(lo / 0x1+1234567890)) >>> 0;
  }
  return h2.toString(16).padStart(8, '0') + h1.toString(16).padStart(8, '0');
}

// Normalize markdown to remove volatile artifacts (JS render race conditions, whitespace noise)
function normalize(md) {
  return (md || '')
    // Strip the server-side fallback placeholder that appears when JS hasn't rendered yet
    .replace(/Code demo fallback when rendering server side!?/gi, '')
    // Strip "Last updated" / "Cập nhật lần cuối" lines (relative dates can drift)
    .replace(/^.*[Cc]ập nhật lần cuối.*$/gm, '')
    .replace(/^.*[Ll]ast [Uu]pdated.*$/gm, '')
    // Collapse runs of whitespace
    .replace(/\s+/g, ' ')
    .trim();
}

const items = $input.all();
return items.map(item => {
  const data = item.json.data || item.json;
  const url = data.metadata?.sourceURL || data.metadata?.url || data.url || item.json.url;
  const title = data.metadata?.title || (url || '').split('/').pop() || 'untitled';
  const markdown = data.markdown || '';
  const normalized = normalize(markdown);
  const lenTag = normalized.length.toString(16).padStart(8, '0');
  const fingerprint = fnv1a64(normalized);
  const contentHash = (lenTag + fingerprint).slice(0, 64);
  const preview = markdown.slice(0, 500);
  return {
    json: {
      source: 'zalo-bot',
      url,
      title,
      content_hash: contentHash,
      content_preview: preview,
      markdown_full: markdown,
      normalized_length: normalized.length,
    }
  };
});

const pages = $json.changedPages || [];
let newCount = 0, changedCount = 0;
const lines = [];
for (const p of pages) {
  const status = p.status || 'unknown';
  if (status === 'new') newCount++;
  else if (status === 'changed') changedCount++;
  lines.push(`- [${status.toUpperCase()}] ${p.title}\n  ${p.url}`);
}
const previews = pages.slice(0, 5).map(p => `### ${p.url}\n${(p.content_preview || '').slice(0, 400)}`).join('\n\n');
return [{
  json: {
    totalChanged: pages.length,
    newCount,
    changedCount,
    changesList: lines.join('\n'),
    previews,
  }
}];

